<?php
// config/game_content.php
// Данные героев и предметов хранятся в базе данных (таблицы `hero` и `item`).
// Таблицы создаются автоматически, а стартовые данные подставляются ОДИН раз
// при первом открытии сайта. Поэтому повторный импорт базы НЕ требуется —
// и дома, и в колледже данные появятся сами.
// Файл подключается из config/heroes_data.php и config/items_data.php.

if (!function_exists('getDB')) {
    require_once __DIR__ . '/db.php';
}

function heroAttrName($attr) {
    $map = ['strength' => 'Сила', 'agility' => 'Ловкость', 'intelligence' => 'Интеллект', 'universal' => 'Универсальный'];
    return $map[$attr] ?? 'Сила';
}

function defaultHeroesSeed() {
    return [
        ['id' => 1, 'name' => 'Pudge', 'attr' => 'strength', 'attack' => 'Ближний бой', 'roles' => 'Позиция 3, Позиция 4', 'base_str' => 25, 'base_agi' => 14, 'base_int' => 16, 'gain_str' => '3.2', 'gain_agi' => '1.5', 'gain_int' => '1.5', 'abilities' => "Meat Hook\nRot\nFlesh Heap\nDismember", 'image_url' => 'https://ru.dotabuff.com/assets/heroes/pudge-d8673aca5ef38b0cff4826c8c7d22e09e8e09b44940a86859c8161553caefa8c.jpg', 'description' => 'На полях Вечной бойни, далеко на юге от Квойджа, тучная фигура упорно трудится под покровом ночи — расчленяет и потрошит павших, сгружая в кучи их конечности и потроха, — чтобы к рассвету поле боя было чисто. В этом проклятом мире ничто не разлагается само по себе — мертвецам не суждено вернуться обратно в землю, и не важно, насколько глубока могила. Окружённый стаями птиц-падальщиков, каждая из которых ждёт своего кусочка мёртвой плоти, мясник упражняется с лезвиями, и с каждым движением они становятся лишь острее. Вжик-вжик-тук. Плоть отсекается от костей, связки и сухожилия разрываются как мокрая бумага. И хоть мясницкое ремесло всегда было по вкусу тучному здоровяку, с годами у него проснулся интерес ещё и к тому, что остаётся после его работы. Сначала кусочек мускула там, потом глоточек крови здесь... Вскоре он впивался в самые крепкие тела подобно грызущей кость собаке. Даже те, кто не питают страха перед жнецом Смерти, предпочитают не связываться с мясником.', 'tips' => 'Используйте Meat Hook для захвата одиночных целей издалека. Способность Rot наносит урон по области вокруг героя — активируйте её в ближнем бою. Герой хорошо работает на позиции поддержки благодаря высокому запасу здоровья.'],
        ['id' => 2, 'name' => 'Centaur Warrunner', 'attr' => 'strength', 'attack' => 'Ближний бой', 'roles' => 'Позиция 3', 'base_str' => 23, 'base_agi' => 15, 'base_int' => 15, 'gain_str' => '4.0', 'gain_agi' => '1.0', 'gain_int' => '1.5', 'abilities' => "Hoof Stomp\nDouble Edge\nRetaliate\nStampede", 'image_url' => 'https://ru.dotabuff.com/assets/heroes/centaur-warrunner-57b9e5d75f9bd84e2651254d28cb50a63e91a3e8699095d16d1776cbff8d80c5.jpg', 'description' => 'Говорят, что жизненный путь кентавра вымощен телами павших. Если это так, то для кентавра по имени Warrunner этот путь был действительно длинным. Многие чужестранцы, повстречав четырёхногих воинов из кланов Друуда, зачастую ошибочно принимают их за простоватых громил. У их языка нет письменной формы, культура бедна на графические символы; в музыке нет чёткой структуры, а в религии — строгих правил и догм. У кентавров лучшее проявление своих мыслей и чувств — это битва. Это самовыражение в чистом виде. И если убийство среди кентавров считается искусством, то самый талантливый из их творцов — Брэдводен.', 'tips' => 'Герой обладает одним из самых высоких показателей прироста силы в игре. Используйте Double Edge для нанесения большого урона, но помните что способность также наносит урон самому герою. Ультимативная способность Stampede позволяет всей команде быстро перемещаться по карте.'],
        ['id' => 3, 'name' => 'Wraith King', 'attr' => 'strength', 'attack' => 'Ближний бой', 'roles' => 'Позиция 1, Позиция 3', 'base_str' => 22, 'base_agi' => 16, 'base_int' => 18, 'gain_str' => '2.8', 'gain_agi' => '1.7', 'gain_int' => '1.6', 'abilities' => "Wraithfire Blast\nVampiric Spirit\nMortal Strike\nReincarnation", 'image_url' => 'https://ru.dotabuff.com/assets/heroes/wraith-king-233a53f103c784de0f480cec4f18dd8490bd6da44357154e4717dfb31ffbb2b3.jpg', 'description' => 'В течение долгих лет король Остарион создавал империю из останков своих врагов. Вечная деспотическая власть стала его навязчивой идеей, полностью охватившей рассудок. Он считал, что башни, построенные рядом с его дворцом, смогут сохранить его жизнь навсегда. Позднее он осознал, что это было глубокое заблуждение... Ведь даже кости однажды обратятся в прах. Глубоко разочарованный недолговечностью плоти, он начал искать более надежный способ, чтобы продлить своё правление и, в конце концов, нашел его.', 'tips' => 'Ультимативная способность Reincarnation позволяет герою воскреснуть после смерти — используйте это преимущество в командных сражениях. Vampiric Spirit создаёт скелетов-воинов, которые помогают в добыче золота и атаке. Герой хорошо подходит для роли основного урона в команде.'],
        ['id' => 7, 'name' => 'Phantom Assassin', 'attr' => 'agility', 'attack' => 'Ближний бой', 'roles' => 'Позиция 1', 'base_str' => 19, 'base_agi' => 23, 'base_int' => 15, 'gain_str' => '2.1', 'gain_agi' => '3.2', 'gain_int' => '1.4', 'abilities' => "Stifling Dagger\nPhantom Strike\nBlur\nCoup de Grace", 'image_url' => 'https://ru.dotabuff.com/assets/heroes/phantom-assassin-7654f46ff00ddaefca29b284c7a70705a0c305250560f0543eaa8539e3d848f8.jpg', 'description' => 'Сёстры Вуали, считающие убийство священной частью естественного цикла жизни, находят новых воспитанниц в гаданиях. О своих жертвах сёстры узнают в медитации и пророческих изречениях. Они не принимают контрактов, и, похоже, не преследуют жертв из-за политики или корысти. Их убийства не выглядят частью какого-то замысла, и могут показаться не связанными между собой: сегодня жертвой станет человек с великой властью, завтра — крестьянин или копатель колодцев.', 'tips' => 'Герой наносит очень высокий урон за счёт критических ударов от способности Coup de Grace. Собирайте предметы на увеличение урона и скорости атаки. Способность Blur даёт шанс уклонения от атак, что делает героя устойчивым в затяжных боях.'],
        ['id' => 8, 'name' => 'Templar Assassin', 'attr' => 'agility', 'attack' => 'Дальний бой', 'roles' => 'Позиция 1', 'base_str' => 18, 'base_agi' => 23, 'base_int' => 20, 'gain_str' => '2.1', 'gain_agi' => '3.2', 'gain_int' => '2.0', 'abilities' => "Refraction\nMeld\nPsi Blades\nPsionic Trap", 'image_url' => 'https://ru.dotabuff.com/assets/heroes/templar-assassin-59dffc687571d6282dd71ab1e5eae130e3c3789b343d06832a0c170cd94b0322.jpg', 'description' => 'Ланайя, Templar Assassin, стала той, кто она есть, благодаря своему врождённому любопытству. Эта обладательница проницательного ума потратила юные годы на тщательное изучение законов природы. Она зачитывалась гримуарами по магии и алхимии, проводила эксперименты, описанные на обугленных страницах Фиолетовых архивов, запоминала наблюдения учёных из смышлёного народца. Тихая и скрытная от природы, она всё больше развивала эти свои навыки, ведь новые знания находились всё труднее.', 'tips' => 'Активируйте Refraction перед вступлением в бой — способность поглощает несколько ударов противника. Используйте Meld для засады: герой становится невидимым и следующая атака наносит повышенный урон. Psionic Trap позволяет замедлять врагов на большой территории карты.'],
        ['id' => 9, 'name' => 'Medusa', 'attr' => 'agility', 'attack' => 'Дальний бой', 'roles' => 'Позиция 1', 'base_str' => 17, 'base_agi' => 18, 'base_int' => 19, 'gain_str' => '1.8', 'gain_agi' => '2.6', 'gain_int' => '1.9', 'abilities' => "Split Shot\nMystic Snake\nMana Shield\nStone Gaze", 'image_url' => 'https://ru.dotabuff.com/assets/heroes/medusa-2d3f561c0312520e3d2b03808b0df8025ea98ec977d9a1701d67ed22e11e2565.jpg', 'description' => '«Красота — страшная сила». Этой мыслью утешала себя самая юная и прелестная горгона с раннего детства, ибо ей единственной из трёх прекрасных дочерей морской богини не довелось родиться бессмертной. Всё изменилось в тот роковой день, когда неизвестные в масках ворвались в обитель горгон и похитили её сестёр, бесстрастные к их красоте и слезам.', 'tips' => 'Герой становится очень сильным в поздней стадии игры — сосредоточьтесь на накоплении предметов. Mana Shield поглощает урон за счёт запаса маны, поэтому собирайте предметы на увеличение интеллекта. Split Shot позволяет одновременно атаковать нескольких врагов, что эффективно против групп противников.'],
        ['id' => 13, 'name' => 'Lion', 'attr' => 'intelligence', 'attack' => 'Дальний бой', 'roles' => 'Позиция 4, Позиция 5', 'base_str' => 18, 'base_agi' => 15, 'base_int' => 22, 'gain_str' => '2.2', 'gain_agi' => '1.5', 'gain_int' => '3.5', 'abilities' => "Earth Spike\nHex\nMana Drain\nFinger of Death", 'image_url' => 'https://ru.dotabuff.com/assets/heroes/lion-aa7c75a15844883581f25be8dca60efd72e7273a7dd8fa9c785c79f6bd7fdf42.jpg', 'description' => 'Некогда Великий магистр демонологии заслужил известность среди своих собратьев, сражаясь на стороне света и справедливости. Но лесть испортила его. Силы мага превосходило лишь его же честолюбие, и демон завлёк его на тёмную сторону, выменяв душу магистра на уважение других. Запятнав душу ужасными преступлениями, маг остался в одиночестве: демон предал его и стал искать выгоды у врагов.', 'tips' => 'Герой обладает двумя способностями обездвиживания: Earth Spike и Hex. Используйте их последовательно для длительного контроля над противником. Ультимативная способность Finger of Death наносит огромный единовременный урон — применяйте её против ослабленных врагов.'],
        ['id' => 14, 'name' => 'Zeus', 'attr' => 'intelligence', 'attack' => 'Дальний бой', 'roles' => 'Позиция 2, Позиция 4', 'base_str' => 19, 'base_agi' => 11, 'base_int' => 22, 'gain_str' => '2.1', 'gain_agi' => '1.2', 'gain_int' => '3.3', 'abilities' => "Arc Lightning\nLightning Bolt\nHeavenly Jump\nThundergod's Wrath", 'image_url' => 'https://ru.dotabuff.com/assets/heroes/zeus-270c72957e96bab2b1ecab445e0f4f62454f61a722085c83c749909b90c3912a.jpg', 'description' => 'Повелитель небес и отец богов видит во всех героях своих буйных, мятежных детей. Неисчислимы свидания со смертными женщинами, где заставала его супруга. Поставила богиня бессмертного перед выбором: «Если нравятся смертные, иди и сам стань среди них. Докажи свою верность, и приму тебя своим мужем бессмертным. Если же нет — иди и умри средь созданий своих».', 'tips' => "Герой наносит высокий магический урон всем противникам на карте с помощью ультимативной способности Thundergod's Wrath. Способности Arc Lightning и Lightning Bolt хорошо сочетаются для быстрого уничтожения врагов. Герой уязвим в ближнем бою — держитесь на безопасном расстоянии."],
        ['id' => 15, 'name' => 'Dark Willow', 'attr' => 'intelligence', 'attack' => 'Дальний бой', 'roles' => 'Позиция 4, Позиция 5', 'base_str' => 17, 'base_agi' => 16, 'base_int' => 26, 'gain_str' => '2.0', 'gain_agi' => '1.6', 'gain_int' => '3.5', 'abilities' => "Bramble Maze\nShadow Realm\nCursed Crown\nTerrorize", 'image_url' => 'https://ru.dotabuff.com/assets/heroes/dark-willow-72b9b406f55446c501688c97f7954ac9c238bd48714cc322ca190d6fc1b6dbc2.jpg', 'description' => 'Детишки обожают рассказывать о чудных похождениях феечек... Ах, если бы они знали, что многие феи — просто коварные гадины! А в их коварном мире немногие похвастаются такой дурной славой, как Миреска Ветреная. Миреска приходилась дочерью одному важному фейскому купцу, и росла она в беспощадном Ревтеле, где каждый без стыда плутовал и убивал.', 'tips' => 'Bramble Maze создаёт зону с кустами, которые обездвиживают вошедших врагов — размещайте её на путях отступления противника. Shadow Realm накапливает урон пока герой невидим. Cursed Crown передаёт оглушение на соседних врагов, что делает героя опасным против сгруппированных противников.'],
        ['id' => 19, 'name' => 'Marci', 'attr' => 'universal', 'attack' => 'Ближний бой', 'roles' => 'Позиция 3, Позиция 4', 'base_str' => 22, 'base_agi' => 20, 'base_int' => 19, 'gain_str' => '2.9', 'gain_agi' => '2.2', 'gain_int' => '1.9', 'abilities' => "Unleash\nSidekick\nRebound\nDispose", 'image_url' => 'https://ru.dotabuff.com/assets/heroes/marci-9a0a2c4d90dc63116a5ba23439d97194915d3abd083cccc226a9b3c21fcdaa81.jpg', 'description' => 'У Марси много обожателей, но о её происхождении известно немногим. Обычно она сопровождает в пути принцессу Мирану, но корни их дружбы сплетены в таких секретах, которые ни одна из них не раскроет без надобности. Для союзников она — беспощадная и честная защитница. Для противников же — бесстрашное препятствие на пути к тем, кого она считает друзьями.', 'tips' => 'Rebound позволяет герою прыгать на союзников и врагов, обеспечивая высокую подвижность. Dispose отбрасывает врага назад — используйте для прерывания вражеских способностей. Sidekick даёт союзнику вампиризм, что полезно для поддержки основного урона команды.'],
        ['id' => 20, 'name' => 'Techies', 'attr' => 'universal', 'attack' => 'Дальний бой', 'roles' => 'Позиция 4, Позиция 5', 'base_str' => 17, 'base_agi' => 14, 'base_int' => 25, 'gain_str' => '2.1', 'gain_agi' => '1.3', 'gain_int' => '3.2', 'abilities' => "Proximity Mines\nStasis Trap\nFocused Detonate\nRemote Mines", 'image_url' => 'https://ru.dotabuff.com/assets/heroes/techies-e199ba8af1a4508668ec6cc16ecc96fe38231a4dd021a72e30d76d14e7e2cdb8.jpg', 'description' => 'За всю историю Устричной бухты никого не ненавидели так, как подрывников Techies. Но — вот незадача — Устричной бухты больше нет. Как и города Тотерина. И даже Охотограда. Вообще, если бы кто-нибудь следил за похождениями подрывников, он бы заметил, что там, где появляются Techies, исчезают города.', 'tips' => 'Расставляйте мины на ключевых точках карты: у входов в лес, у рун и на путях отступления. Stasis Trap обездвиживает врагов, наступивших на неё — комбинируйте с минами для максимального урона. Герой требует тщательного планирования расстановки мин заранее.'],
        ['id' => 21, 'name' => 'Batrider', 'attr' => 'universal', 'attack' => 'Дальний бой', 'roles' => 'Позиция 3, Позиция 4', 'base_str' => 25, 'base_agi' => 18, 'base_int' => 18, 'gain_str' => '2.9', 'gain_agi' => '1.5', 'gain_int' => '1.8', 'abilities' => "Sticky Napalm\nIncendiary Gel\nFlamebreak\nFirefly", 'image_url' => 'https://ru.dotabuff.com/assets/heroes/batrider-2cea2260556b67fe7d44f4b325cf6673d55cb03d4b419f4e68ac9acab243c09d.jpg', 'description' => 'Среди тварей, обитающих в джунглях Йама Раскав, такой вещи, как гармония, попросту нет. Любое проявление слабости приведёт к мгновенной смерти от клювов, когтей, жвал или копыт. Поговаривают, что давным-давно, когда Batrider ещё был простым пареньком, выкапывающим сорняки с семейного поля, его схватила огромная летучая мышь, искавшая себе пищу.', 'tips' => 'Накладывайте Sticky Napalm несколько раз перед применением других способностей — каждый накопленный эффект на враге увеличивает получаемый им урон от физических и магических атак. Firefly оставляет огненный след при полёте — используйте для нанесения урона по области. Ультимативная способность позволяет захватить врага и тащить его за собой.'],
    ];
}

function defaultItemsSeed() {
